#include <stdio.h>
#include <stdlib.h>
/* 
    自定义结构实现队列：使用循环队列

 */


//声明队列对应的结构体
typedef struct{

    int *data;
    int capacity; //记录存储的最大容量
    int size ; //记录存储的元素的个数
    int front ;  //记录要出队的索引位置
    int rear;  //记录入队后的索引位置


}Queue;



// 初始化队列
void initQueue(Queue *queue, size_t capacity)
{
    queue->data = (int *)malloc(capacity * sizeof(int));
    queue->capacity = capacity;
    queue->size = 0;
    queue->front = 0;
    queue->rear = 0;
}

// 返回队列内元素个数
size_t getSize(const Queue *queue)
{
    return queue->size;    
}

// 添加新元素
void enqueue(Queue *queue, int element)
{
    if(queue->size == queue->capacity){
        //容量已满
        printf("队列已满，入队失败\n");
        return;
    }

    queue->data[queue->rear] = element;
    queue->size++;
    //queue->rear++; //存在问题，需要使用下面的方式替换

    queue->rear = (queue->rear + 1) % queue->capacity;
}

// 元素出队列
int dequeue(Queue *queue)
{
    // if(queue->front == queue->rear);//此语句满足的情况：① 队列为空 ② 队列已满
    if(queue->size == 0){
        printf("队列为空，出队失败\n");
        return -1;
    }

    int dequeueData = queue->data[queue->front];
    queue->size--;

    queue->front = (queue->front + 1) % queue->capacity;

    return dequeueData;

}

// 释放队列内存
void destroyQueue(Queue *queue)
{
    free(queue->data);
    queue->data = NULL;
    queue->capacity = 0;
    queue->size = 0;
    queue->front = 0;
    queue->rear = 0;
}


//遍历队列
void printQueue(Queue *queue){

    for(int i = queue->front,j = 0;j < queue->size;i++,j++){


        printf("%d  ",queue->data[i % queue->capacity]);
    }

    printf("\n");


}




int main()
{

    Queue myQueue;

    initQueue(&myQueue,3);

    enqueue(&myQueue,1);
    enqueue(&myQueue,2);
    enqueue(&myQueue,3);
    enqueue(&myQueue,4); //已满，未入队

    printQueue(&myQueue);

    printf("出队，元素是：%d\n",dequeue(&myQueue));
    printf("出队，元素是：%d\n",dequeue(&myQueue));

    printQueue(&myQueue);

    enqueue(&myQueue,5);
    enqueue(&myQueue,6);

    printQueue(&myQueue);


    getchar();


    return 0;
}

