# 冒泡排序

```c:数据结构.md

#include <stdio.h>

/* 

    冒泡排序:实现从小到大排序
 */

void bubbleSort(int arr[],int size){

    //外层循环：控制轮数
    for(int i = 0;i < size - 1;i++){

        //内层循环：依次比较相邻的两个元素的大小
        for(int j = 0;j < size - 1 - i;j++){

            if(arr[j] > arr[j + 1]){
                //交互j 和 j+1索引位置的元素
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;

            }

        }

    }


}


int main(){

    int arr[] = {23,45,2,46,77,2,99,-9,-32,0,66};

    int size = sizeof(arr) / sizeof(int);
    //遍历
    for(int i = 0;i < size;i++){
        printf("%d  ",arr[i]);
    }

    printf("\n");

    //排序
    bubbleSort(arr,size);


    //遍历
    for(int i = 0;i < size;i++){
        printf("%d  ",arr[i]);
    }

    printf("\n");

    getchar();

    return 0;
}
