# 快速排序

```c:数据结构.md

#include <stdio.h>

/*

    快速排序:实现从小到大排序
 */

void quickSort(int arr[], int size)
{

    subSort(arr, 0, size - 1);
}

void subSort(int arr[], int start, int end)
{

    if (start < end)
    {
        int base = arr[start];
        int low = start;
        int high = end + 1;

        while (1)
        {

            while (low < end && arr[++low] <= base)
                ; // 找到从前往后第1个比base大的元素
            while (high > start && arr[--high] >= base)
                ; // 找到从后往前第1个比base小的元素

            if (low < high)
            {
                // 交换low和high位置的元素
                int temp = arr[low];
                arr[low] = arr[high];
                arr[high] = temp;
            }
            else
            {
                break;
            }
        }

        // 交换start和high索引位置上的元素
        int temp1 = arr[start];
        arr[start] = arr[high];
        arr[high] = temp1;

        // 递归调用
        subSort(arr, start, high - 1); // 前半段继续排序
        subSort(arr, high + 1, end);   // 后半段继续排序
    }
}

int main()
{

    int arr[] = {23, 45, 2, 46, 77, 2, 99, -9, -32, 0, 66};

    int size = sizeof(arr) / sizeof(int);
    // 遍历
    for (int i = 0; i < size; i++)
    {
        printf("%d  ", arr[i]);
    }

    printf("\n");

    // 排序
    quickSort(arr, size);

    // 遍历
    for (int i = 0; i < size; i++)
    {
        printf("%d  ", arr[i]);
    }

    printf("\n");

    getchar();

    return 0;
}
```

