#include <stdio.h>
#include <stdlib.h>

/* 

  自定义实现栈结构：使用顺序存储结构实现--> 顺序栈

 */

typedef struct {

    //存储数据的指针
    int *data;
    //指明存储容器的容量
    size_t capacity;
    //指明存储容器中实际存储的数据量
    size_t size;

}Stack;



// 初始化栈
void initStack(Stack *stack, size_t capacity)
{
    stack->data = (int *)malloc(capacity *sizeof(int));//动态内存分配
    if(stack->data == NULL){
        printf("内存分配失败\n");
        exit(1);
    }

    stack->capacity = capacity;         
    stack->size = 0;


}

// 返回栈内元素个数
size_t getSize(const Stack *stack)
{

    return stack->size;
}

// 添加新元素
void push(Stack *stack, int element)
{
    //考虑是否存满了
    if(stack->size == stack->capacity){
        //扩容
        resizeCapacity(stack,stack->capacity + stack->capacity >> 1); //扩容为原来的1.5倍
        printf("容量已满，进行扩容操作\n");
    }

    stack->data[stack->size] = element;
    stack->size++;

}


void resizeCapacity(Stack *stack,int newCapacity){

    stack->data = (int *)realloc(stack->data,newCapacity * sizeof(int)); //扩容操作
    stack->capacity = newCapacity; //指明新的容量值

}



// 栈顶元素出栈并返回
int pop(Stack *stack)
{
    //判断是否为空
    if(stack->size == 0){
        printf("当前栈为空,弹栈失败\n");
        return -1;
    }

    // int popElement = stack->data[stack->size-1];
    // stack->size--;

    // return popElement;

    return stack->data[--stack->size];//


//这是一个前缀自减操作。它的作用是将 stack->size 的值减一，然后返回这个新的值。
//例如，如果 stack->size 原本是 3，经过 --stack->size 处理后，
//stack->size 会变为 2。这意味着我们将要弹出栈中索引为 2 的元素（即第三个元素，因为索引从 0 开始）。
}

// 释放栈内存
void destroyStack(Stack *stack)
{
    free(stack->data);
    stack->data = NULL;
    stack->capacity = 0;
    stack->size = 0;
}

//遍历栈中的元素
void print(Stack *stack){
    for(int i = 0;i < stack->size;i++){
        printf("%d  ",stack->data[i]);
    }
    printf("\n");

}


int main()
{

    //声明结构体变量
    Stack myStack;

    initStack(&myStack,3);

    push(&myStack,1);
    push(&myStack,2);
    push(&myStack,3);
    push(&myStack,4);


    printf("栈中元素的个数为：%d\n",getSize(&myStack));

    print(&myStack);

    printf("弹栈，弹出的数据是：%d\n",pop(&myStack));
    printf("弹栈，弹出的数据是：%d\n",pop(&myStack));


    print(&myStack);

    getchar();

    return 0;
}

```

##  线性结构之队列

###  基本概念

队列(Queue)：也是操作受限的线性表，限制为仅允许在表的一端进行插入(入队或进队），在表的另一端进行删除(出队或离队)操作。

\- 队首(front) ：允许进行删除的一端称为队首。

\- 队尾(rear)： 允许进行插入的一端称为队尾。

在空队列中依次加入元素a1,a2, …, an之后，a1是队首元素，an是队尾元素。显然退出队列的次序也只能是a1,a2, …, an。队列，是一种先进先出(First In First Out ，简称FIFO)的线性结构。类似于生活中的排队行为。

![image-20241111205010221](https://s1.vika.cn/space/2024/11/12/b4e17e3fbd7d4f78815a4f01eb85cb5f)

队列中没有元素时，称为空队列。

### 队列的存储结构

可用顺序表(数组)和链表来存储队列，队列按存储结构可分为顺序队列和链式队列两种。

###  功能定义

```c:数据结构.md
初始化队列
void initQueue(Queue *queue, size_t capacity)
返回队列内元素个数
size_t getSize(const Queue *queue)
添加新元素
void enqueue(Queue *queue, int element)
元素出队列
int dequeue(Queue *queue)
释放队列内存
void destroyQueue(Queue *queue)
遍历队列
void printQueue(Queue *queue)

```

```c:数据结构.md

#include <stdio.h>
#include <stdlib.h>
/* 
    自定义结构实现队列：使用循环队列

 */


//声明队列对应的结构体
typedef struct{

    int *data;
    int capacity; //记录存储的最大容量
    int size ; //记录存储的元素的个数
    int front ;  //记录要出队的索引位置
    int rear;  //记录入队后的索引位置


}Queue;



// 初始化队列
void initQueue(Queue *queue, size_t capacity)
{
    queue->data = (int *)malloc(capacity * sizeof(int));
    queue->capacity = capacity;
    queue->size = 0;
    queue->front = 0;
    queue->rear = 0;
}

// 返回队列内元素个数
size_t getSize(const Queue *queue)
{
    return queue->size;    
}

// 添加新元素
void enqueue(Queue *queue, int element)
{
    if(queue->size == queue->capacity){
        //容量已满
        printf("队列已满，入队失败\n");
        return;
    }

    queue->data[queue->rear] = element;
    queue->size++;
    //queue->rear++; //存在问题，需要使用下面的方式替换

    queue->rear = (queue->rear + 1) % queue->capacity;
}

// 元素出队列
int dequeue(Queue *queue)
{
    // if(queue->front == queue->rear);//此语句满足的情况：① 队列为空 ② 队列已满
    if(queue->size == 0){
        printf("队列为空，出队失败\n");
        return -1;
    }

    int dequeueData = queue->data[queue->front];
    queue->size--;

    queue->front = (queue->front + 1) % queue->capacity;

    return dequeueData;

}

// 释放队列内存
void destroyQueue(Queue *queue)
{
    free(queue->data);
    queue->data = NULL;
    queue->capacity = 0;
    queue->size = 0;
    queue->front = 0;
    queue->rear = 0;
}


//遍历队列
void printQueue(Queue *queue){

    for(int i = queue->front,j = 0;j < queue->size;i++,j++){


        printf("%d  ",queue->data[i % queue->capacity]);
    }

    printf("\n");


}




int main()
{

    Queue myQueue;

    initQueue(&myQueue,3);

    enqueue(&myQueue,1);
    enqueue(&myQueue,2);
    enqueue(&myQueue,3);
    enqueue(&myQueue,4); //已满，未入队

    printQueue(&myQueue);

    printf("出队，元素是：%d\n",dequeue(&myQueue));
    printf("出队，元素是：%d\n",dequeue(&myQueue));

    printQueue(&myQueue);

    enqueue(&myQueue,5);
    enqueue(&myQueue,6);

    printQueue(&myQueue);


    getchar();


    return 0;
}

```

