#  二分查找

二分查找（Binary Search）是一种高效的搜索算法，通常用于有序数据集中查找目标元素。其原理是通过将数据集划分为两半并与目标进行比较，以确定目标在哪一半中，从而逐步缩小搜索范围，直到找到目标元素或确定不存在。基本原理如下：

（1）**选择中间元素：** 在有序数据集中，选择数组的中间元素。

（1）**比较目标：** 将中间元素与目标元素进行比较。

（2）**查找成功：** 如果中间元素等于目标元素，则查找成功，返回中间元素的索引。

（3）**缩小搜索范围：** 对于一个升序的数据集，如果中间元素大于目标元素，说明目标可能在左半部分；如果中间元素小于目标元素，说明目标可能在右半部分。根据比较结果，将搜索范围缩小到一半，继续查找。

（4）**重复步骤：** 重复上述步骤，不断将搜索范围缩小，直到找到目标元素或搜索范围为空。

​                                   

```c:数据结构.md

#include <stdio.h>

/* 

    使用二分查找法，查找数组中的元素
 */


int binarySearch(int arr[],int size,int target){

    int low = 0;
    int high = size - 1;


    while(low <= high){

        int middle = (low + high) / 2;
        if(arr[middle] == target){
            return middle;
        }else if(arr[middle] > target){
            high = middle - 1;
        }else{
            low = middle + 1;
        }

    }

    //表示未找到
    return -1;

}


int main()
{

    int arr[] = {4,7,9,12,16,19,22,28,34,57,69,78,90};
    int target = 12;
    target = 91;
    int size = sizeof(arr) / sizeof(int);

    int targetIndex = binarySearch(arr,size,target);
    if(targetIndex == -1){
        printf("未找到\n");
    }else{
        printf("找到了%d，对应的索引为%d\n",target,targetIndex);
    }

    getchar();

    return 0;
}
```

# 冒泡排序

```c:数据结构.md

#include <stdio.h>

/* 

    冒泡排序:实现从小到大排序
 */

void bubbleSort(int arr[],int size){

    //外层循环：控制轮数
    for(int i = 0;i < size - 1;i++){

        //内层循环：依次比较相邻的两个元素的大小
        for(int j = 0;j < size - 1 - i;j++){

            if(arr[j] > arr[j + 1]){
                //交互j 和 j+1索引位置的元素
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;

            }

        }

    }


}


int main(){

    int arr[] = {23,45,2,46,77,2,99,-9,-32,0,66};

    int size = sizeof(arr) / sizeof(int);
    //遍历
    for(int i = 0;i < size;i++){
        printf("%d  ",arr[i]);
    }

    printf("\n");

    //排序
    bubbleSort(arr,size);


    //遍历
    for(int i = 0;i < size;i++){
        printf("%d  ",arr[i]);
    }

    printf("\n");

    getchar();

    return 0;
}
```

# 快速排序

```c:数据结构.md

#include <stdio.h>

/*

    快速排序:实现从小到大排序
 */

void quickSort(int arr[], int size)
{

    subSort(arr, 0, size - 1);
}

void subSort(int arr[], int start, int end)
{

    if (start < end)
    {
        int base = arr[start];
        int low = start;
        int high = end + 1;

        while (1)
        {

            while (low < end && arr[++low] <= base)
                ; // 找到从前往后第1个比base大的元素
            while (high > start && arr[--high] >= base)
                ; // 找到从后往前第1个比base小的元素

            if (low < high)
            {
                // 交换low和high位置的元素
                int temp = arr[low];
                arr[low] = arr[high];
                arr[high] = temp;
            }
            else
            {
                break;
            }
        }

        // 交换start和high索引位置上的元素
        int temp1 = arr[start];
        arr[start] = arr[high];
        arr[high] = temp1;

        // 递归调用
        subSort(arr, start, high - 1); // 前半段继续排序
        subSort(arr, high + 1, end);   // 后半段继续排序
    }
}

int main()
{

    int arr[] = {23, 45, 2, 46, 77, 2, 99, -9, -32, 0, 66};

    int size = sizeof(arr) / sizeof(int);
    // 遍历
    for (int i = 0; i < size; i++)
    {
        printf("%d  ", arr[i]);
    }

    printf("\n");

    // 排序
    quickSort(arr, size);

    // 遍历
    for (int i = 0; i < size; i++)
    {
        printf("%d  ", arr[i]);
    }

    printf("\n");

    getchar();

    return 0;
}
```

